import{_ as e,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Safety/user-rate-limits.md","filePath":"th-TH/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"th-TH/Safety/user-rate-limits.md"};function o(p,t,n,u,c,h){return l(),s("div",null,[...t[0]||(t[0]=[d('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits ควบคุมว่า regular users หรือ visitors จะ upload files จาก homepage ได้ถี่แค่ไหน ช่วยลดการ abuse ของ public upload pages</p><p>Feature นี้มีผลเฉพาะ homepage uploads Admin uploads และ uploads ที่ทำด้วย API Tokens จะไม่ถูกจำกัดโดย user rate limits</p><h2 id="ตั้งค่าที่ไหน" tabindex="-1">ตั้งค่าที่ไหน <a class="header-anchor" href="#ตั้งค่าที่ไหน" aria-label="Permalink to &quot;ตั้งค่าที่ไหน&quot;">​</a></h2><p>เปิด admin panel แล้วไปที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="User rate limit settings" loading="lazy"></p><h2 id="enable-rate-limits" tabindex="-1">Enable Rate Limits <a class="header-anchor" href="#enable-rate-limits" aria-label="Permalink to &quot;Enable Rate Limits&quot;">​</a></h2><p>หลังเปิด <code>Enable Rate Limits</code> ImgBed จะ track recent uploads ตาม uploader IP address</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>นับ upload records ย้อนหลังนานแค่ไหน</td></tr><tr><td>Max file count</td><td>20</td><td>จำนวน files สูงสุดที่ allowed ใน detection window</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>ขนาดสูงสุดของ file เดียว</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Total upload size สูงสุดใน detection window</td></tr></tbody></table><p>ตัวอย่าง ถ้าตั้ง 1.5 hour window, 20 files, 20 MB ต่อ file และ 200 MB total uploads จาก IP เดียวกันจะถูก block เมื่อเกิน limit ใด limit หนึ่ง</p><h2 id="excluding-file-types" tabindex="-1">Excluding File Types <a class="header-anchor" href="#excluding-file-types" aria-label="Permalink to &quot;Excluding File Types&quot;">​</a></h2><p><code>Excluded upload file types</code> block regular users หรือ visitors ไม่ให้ upload file categories ที่เลือก</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif และ image files ใกล้เคียง</td></tr><tr><td>Videos</td><td>mp4, webm, mov และ video files ใกล้เคียง</td></tr><tr><td>Audio</td><td>mp3, flac, wav และ audio files ใกล้เคียง</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx และ document files ใกล้เคียง</td></tr><tr><td>Other</td><td>Files นอก categories ด้านบน เช่น zip, rar, exe, apk</td></tr></tbody></table><p>ค่าเริ่มต้นคือไม่มี type ถูกเลือก แปลว่า allowed</p><p>เมื่อคลิก type จะ highlight ซึ่งหมายถึง type นั้นถูก block</p><p>ถ้าเลือก <code>Other</code> visitors ที่ upload zip หรือ rar files จะถูก block และเห็นข้อความว่า file type นี้ไม่ supported</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>เมื่อ limit ถูก trigger users จะเห็น message ที่ตรงกับสถานการณ์:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>File ใหญ่เกินไป ควร compress ก่อน upload</td></tr><tr><td>File type blocked</td><td>File type นี้ไม่ supported ให้เอาออกแล้วลองใหม่</td></tr><tr><td>Uploads too frequent</td><td>Recent uploads ถี่เกินไป พร้อมแสดง retry time</td></tr><tr><td>Total size too high</td><td>Recent total upload size สูงเกินไป พร้อมแสดง retry time</td></tr></tbody></table><h2 id="ควร-enable-เมื่อไร" tabindex="-1">ควร Enable เมื่อไร <a class="header-anchor" href="#ควร-enable-เมื่อไร" aria-label="Permalink to &quot;ควร Enable เมื่อไร&quot;">​</a></h2><p>Enable user rate limits ถ้า upload homepage เปิดให้ public เข้าถึงได้</p><p>เหตุผลที่พบบ่อย:</p><ul><li>กังวล scripted bulk uploads</li><li>ต้องการจำกัด large visitor uploads</li><li>ต้องการให้ regular users upload ได้เฉพาะ images ไม่ใช่ archives หรือ installers</li><li>ต้องการให้ public upload ยังใช้งานได้ แต่ควบคุม resource usage</li></ul><p>ถ้า site ใช้เองเท่านั้น หรือมีเฉพาะ administrators ที่ upload ได้ สามารถปิดไว้ได้</p>',28)])])}const f=i(r,[["render",o]]);export{b as __pageData,f as default};
